#include<bits/stdc++.h>
using namespace std;
const int N=100010;
int n,m;
struct two_sat
{
    int low[N*2],dfn[N*2],dfncnt,scccnt,color[N*2];
    bool instk[N*2];
    vector<int> mp[N*2];
    stack<int> stk;
    int flag;
    two_sat():flag(0){}
    void clear()
    {
        memset(low,0,sizeof(low));
        memset(dfn,0,sizeof(dfn));
        memset(color,0,sizeof(color));
        memset(instk,0,sizeof(instk));
        for(int i=1;i<=(n<<1);i++)
        {
            mp[i].clear();
        }
        while(!stk.empty())
        {
            stk.pop();
        }
        flag=0;
        dfncnt=scccnt=0;
    }
    void add(int x,int y)
    {
        flag=0;
        mp[x].push_back(y);
    }
    void add(int i,int a,int j,int b)
    {
        flag=0;
        mp[i+n*(a^1)].push_back(j+n*b);
        mp[j+n*(b^1)].push_back(i+n*a);
    }
    void tarjan(int x)
    {
        low[x]=dfn[x]=++dfncnt;
        stk.push(x);
        instk[x]=1;
        for(int v:mp[x])
        {
            if(!dfn[v])
            {
                tarjan(v);
                low[x]=min(low[x],low[v]);
            }
            else if(instk[v])
            {
                low[x]=min(low[x],dfn[v]);
            }
        }
        if(low[x]==dfn[x])
        {
            scccnt++;
            int top;
            do
            {
                top=stk.top();
                stk.pop();
                color[top]=scccnt;
                instk[top]=0;
            }while(top!=x);
        }
    }
    void solve()
    {
        for(int i=1;i<=(n<<1);i++)
        {
            if(!dfn[i])
            {
                tarjan(i);
            }
        }
        flag=1;
    }
    bool possible()
    {
        if(flag==0)
        {
            solve();
        }
        for(int i=1;i<=n;i++)
        {
            if(color[i]==color[i+n])
            {
                return false;
            }
        }
        return true;
    }
    bool getans(int x)
    {
        if(flag==0)
        {
            solve();
        }
        return color[x]<color[x+n];
    }
}_2sat;
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%d%d",&n,&m);
        _2sat.clear();
        for(int I=1;I<=m;I++)
        {
            string a,b;
            cin>>a>>b;
            int i=atoi(a.substr(1,a.size()-1).c_str()),x=(a[0]=='h'),j=atoi(b.substr(1,b.size()-1).c_str()),y=(b[0]=='h');
            _2sat.add(i,x,j,y);
        }
        if(_2sat.possible())
        {
            printf("GOOD\n");
        }
        else
        {
            printf("BAD\n");
        }
    }
    return 0;
}
